impl Solution { pub fn min_cost(mut arr: Vec<i32>, mut brr: Vec<i32>, k: i64) -> i64 { let black_c1 = arr.iter().zip(brr.iter()).map(|(a, b)| (a - b).abs() as i64).sum::<i64>(); arr.sort_unstable(); brr.sort_unstable(); let black_c2 = k + arr.iter().zip(brr.iter()).map(|(a, b)| (a - b).abs() as i64).sum::<i64>(); black_c1.min(black_c2) } }